INSERT INTO `maintenance_comments` (`id`, `maintenance_request_id`, `user_id`, `note`, `created_at`, `updated_at`) VALUES
(1, 1, 15, 'الرجاء ارسال رقم  جوال العميل ', '2025-10-25 12:14:00', '2025-10-25 12:14:00'),
(2, 1, 21, '0569969006', '2025-10-25 12:17:53', '2025-10-25 12:17:53'),
(3, 1, 15, 'تم التواصل مع العميل وتم تحديد الموعد يوم السبت 1/11/2025', '2025-10-27 14:56:13', '2025-10-27 14:56:13'),
(4, 3, 20, 'تم تحديد موعد للعميل بتايخ 18 / 10 /2025 ولم يتم الذهاب \nوتم تحديد موعد جديد 1/11/2025  برجاء التواصل مع العميل قبل الذهاب بساعة', '2025-10-27 19:23:16', '2025-10-27 19:23:16'),
(5, 3, 15, 'سيتم الدهاب للموقع يوم السبت 1/11/2025', '2025-10-30 12:19:25', '2025-10-30 12:19:25'),
(6, 2, 15, 'الصيانة يوم الاثنين 2025/11/3 ', '2025-10-30 12:26:52', '2025-10-30 12:26:52'),
(7, 3, 20, 'يوجد مشكلة ايضا بمقاس الفرن ', '2025-10-30 19:08:56', '2025-10-30 19:08:56'),
(8, 9, 21, 'https://maps.app.goo.gl/oPnL5wiuqTGt6kk47?g_st=iw  ', '2025-11-10 11:19:38', '2025-11-10 11:19:38'),
(9, 3, 15, 'تم الدهاب للعميل والتواصل معه  وتم اخباره ان في عامل من طرفهم فك باب الزجاج وانكسر \nوتم الاقتراح على العميل ان يتبدل الى باب مفصلي لتفادي فك الجبس من جديد', '2025-11-11 09:43:53', '2025-11-11 09:43:53'),
(10, 12, 14, 'صيانة مستعجلة لباب العائلة يوجد مشكلة في القفل  معالجة الكيلون في أسرع وقت', '2025-11-13 15:37:45', '2025-11-13 15:37:45'),
(11, 13, 14, 'التواصل على هذا الرقم 0561777862  في حال عدم رد الرقم الاساسي\nالعميل يعمل في منطقة بعيدة <', '2025-11-15 13:28:21', '2025-11-15 13:28:21');
INSERT INTO `maintenance_requests` (`id`, `project_id`, `showroom_id`, `client_id`, `created_by`, `requested_by`, `request_date`, `acknowledged_at`, `expected_start_at`, `actual_start_at`, `expected_end_at`, `actual_end_at`, `client_confirmation_file`, `details`, `images`, `status`, `current_owner_role`, `current_owner_user_id`, `sent_to_owner_at`, `received_by_owner_at`, `closed_at`, `created_at`, `updated_at`) VALUES
(1, NULL, 4, 15, 21, NULL, '2025-10-23', NULL, NULL, NULL, NULL, NULL, NULL, 'باب السور لون الباب عليه مثل الغبار اللون تغير ', '[\"maintenance-requests\\/2025\\/10\\/01K87VRQTMKW2168A7A23060CS.jpg\"]', 'new', NULL, NULL, NULL, NULL, NULL, '2025-10-23 09:23:14', '2025-10-23 09:23:14'),
(2, NULL, 4, 20, 21, NULL, '2025-10-27', NULL, NULL, NULL, NULL, NULL, NULL, 'تم ارسال فيديو بالواتس\nالباب مابسكر \nمشكلة بالمفصلة السفليه ', '[\"maintenance-requests\\/2025\\/10\\/01K8JCFH663E5AWT7NBJ72CZJV.mp4\"]', 'new', NULL, NULL, NULL, NULL, NULL, '2025-10-27 10:52:09', '2025-10-27 11:27:43'),
(3, NULL, 4, 24, 20, NULL, '2025-10-27', NULL, NULL, NULL, NULL, NULL, NULL, 'زجاج الباب السحاب للجاكوزي اتكسر والعميل محتاج يعرف سبب الكسر  وهل الباب خبط بالجدار ولا الى كسره الفنين الى كانو بيدخلوا البانيو لانو اتكسر وهما بالداخل وسبب ليهم جروح  وينتظر الفنين عندنا عشان يشوفوا السكة واصلة للاخر ولا ايش المشكلة علما بان السيفتى المفروض يوقف الباب قبل الجدار حسب كلام العميل ', '[\"maintenance-requests\\/2025\\/10\\/01K8K71JEWNJ2WY3FTJXP7WFG0.jpg\"]', 'new', NULL, NULL, NULL, NULL, NULL, '2025-10-27 19:11:57', '2025-10-27 19:11:57'),
(5, NULL, 4, 29, 20, NULL, '2025-11-02', '2025-11-09 18:44:52', '2025-11-15 00:00:00', NULL, NULL, NULL, NULL, 'لديه مشكلة فى الشبك التور حيث صار من المنتصف غير محكم الاغلاق كما بالفيديو المرفق وبالتالى صار يدخل غبار ', '[\"maintenance-requests\\/2025\\/11\\/01K92B7EH6N1Z5DY5F1CVFYD5F.mp4\"]', 'new', 'factory_manager', 1, NULL, '2025-11-09 18:44:52', NULL, '2025-11-02 16:13:40', '2025-11-09 18:45:19'),
(6, NULL, 4, 36, 21, NULL, '2025-11-04', '2025-11-11 09:26:51', '2025-11-16 00:00:00', '2025-11-17 00:00:00', '2025-11-17 00:00:00', '2025-11-17 00:00:00', NULL, 'مشكله في الأبواب وقت الفتح و الاغلاق\nالمقابض فيها صداء', '[]', 'completed', 'factory_manager', 15, NULL, '2025-11-11 09:26:51', '2025-11-17 07:23:56', '2025-11-04 11:15:44', '2025-11-17 07:23:56'),
(7, NULL, 4, 35, 20, NULL, '2025-11-04', '2025-11-11 09:30:57', '2025-11-22 00:00:00', '2025-11-16 00:00:00', '2025-11-16 00:00:00', '2025-11-15 00:00:00', NULL, 'لدى العميل مشكلة فى فتح الباب الخارجى الرئيسي ويحتاج الكالون الى وزنية ', '[\"maintenance-requests\\/2025\\/11\\/01K96ZCFGADPZ3SQMHW7FF3CQ0.mp4\"]', 'completed', 'factory_manager', 15, NULL, '2025-11-11 09:30:57', '2025-11-16 07:49:50', '2025-11-04 11:22:54', '2025-11-16 07:49:50'),
(8, NULL, 4, 48, 13, NULL, '2025-11-09', '2025-11-11 09:34:29', '2025-11-12 00:00:00', NULL, NULL, NULL, NULL, 'الابواب : 1- عند تركيب الباب لاول مرة تم تركيبه مقلوب, وعند تعديله تصدع مكان القفل ومع فتح وتسكير الباب انكسر كما موضح في الصورة  بسبب التصدعات و عدم تثبيت المسامير بشكل جيد \n2- منذ تركيب الباب لاول مرة والفريم جهة المفصلات مكسور كما موضح في الصورة وتم طلب صيانة له اكثر من مرة وعند ذهاب العمال للموقع يتم نسيان اصلاحه \nالدرابزين: تم عمل له صيانة اكثر من مرة ولكن مازالت التشققات تظهر من جديد كما موضح في الصور ', '[\"maintenance-requests\\/2025\\/11\\/01K9MN1CXY72PZHEHGVD15ZZDT.jpeg\",\"maintenance-requests\\/2025\\/11\\/01K9MQN5JX3A8WPBAZTTMMTMS8.jpeg\",\"maintenance-requests\\/2025\\/11\\/01K9MQN5JYRCFAG4ESV00MXMXA.jpeg\",\"maintenance-requests\\/2025\\/11\\/01K9MQN5JZBERJ0N3Z71HY3P2K.jpeg\",\"maintenance-requests\\/2025\\/11\\/01K9MQN5JZBERJ0N3Z71HY3P2M.jpeg\",\"maintenance-requests\\/2025\\/11\\/01K9MQN5K0JVRFA827QB7KZNSZ.jpeg\"]', 'new', 'factory_manager', 15, NULL, '2025-11-11 09:34:29', NULL, '2025-11-09 18:51:27', '2025-11-11 09:34:34'),
(9, NULL, 4, 50, 21, NULL, '2025-11-10', '2025-11-10 10:32:28', '2025-11-13 00:00:00', '2025-11-12 00:00:00', '2025-11-11 00:00:00', '2025-11-12 00:00:00', NULL, 'مشكلة بالكالون\nموقع البيت\nhttps://maps.app.goo.gl/oPnL5wiuqTGt6kk47?g_st=iw ', '[\"maintenance-requests\\/2025\\/11\\/01K9P8QEAQA331N85A6SHKZAP5.mp4\"]', 'completed', 'factory_manager', 15, NULL, '2025-11-10 10:32:28', '2025-11-12 08:06:53', '2025-11-10 09:54:47', '2025-11-12 08:06:53'),
(12, NULL, 4, 51, 14, NULL, '2025-11-10', '2025-11-16 07:38:53', '2025-11-19 00:00:00', NULL, NULL, NULL, NULL, '* باب مدخل العائلة / سقوط المقبض + تقشر المقبض > اضافة دهان + الربل أسفل الباب مفكوك + قفل الباب اصلاح الكيلون\n* باب الفولدنج /  أسفل الباب الربل مفكوك + الحديد من الأسفل غير ثابته\n* باب الديوانية / الربل مفكوك + لا يغلق جيدأً وزنية\n\n* تركيب التول لأبواب الفولدنج\n\n# تحديد موعد بعد انتهاء شركة التنظيف اي بعد تاريخ 19/11/2025#\n\nالباب اليومي تصليح مستعجل لان الكيلون لا يقفل و المكان ما ينفع يظل مفتوح فيه أغراضهم', '[\"maintenance-requests\\/2025\\/11\\/01K9PPG2GMEQF4R3F7TA4HWM4J.mp4\",\"maintenance-requests\\/2025\\/11\\/01K9PPG2GRND1BYZKYPRC2NC2E.mp4\",\"maintenance-requests\\/2025\\/11\\/01K9PPG2GWT7B3397G7PN1NJSE.mp4\",\"maintenance-requests\\/2025\\/11\\/01K9PPG2H2A6KQYSXY07K4SJM1.mp4\",\"maintenance-requests\\/2025\\/11\\/01K9PPG2H8B32HHRN30A6HS9GW.mp4\"]', 'new', 'factory_manager', 15, '2025-11-10 13:55:26', '2025-11-16 07:38:53', NULL, '2025-11-10 13:55:26', '2025-11-16 07:39:10'),
(13, NULL, 4, 58, 14, NULL, '2025-11-15', '2025-11-17 07:22:52', '2025-11-16 00:00:00', '2025-11-17 00:00:00', '2025-11-16 00:00:00', '2025-11-17 00:00:00', NULL, 'يحتاج قص جزء بسيط لسطح بورسلان جوانب الفرن ليتمكن من وضعه في مكانه الصحيح', '[\"maintenance-requests\\/2025\\/11\\/01KA3GTP5FYX45RYN66KGC1R24.jpeg\",\"maintenance-requests\\/2025\\/11\\/01KA3GTP5HEWWPVQ1SWGEV639V.jpeg\"]', 'completed', 'factory_manager', 15, '2025-11-15 13:26:30', '2025-11-17 07:22:52', '2025-11-17 07:23:24', '2025-11-15 13:26:30', '2025-11-17 07:23:24');
